DEFAULT_TIMEOUT_SECONDS = 5

class RuntimeConfig:
    def __init__(self, base_url: str, timeout_seconds: int = DEFAULT_TIMEOUT_SECONDS) -> None:
        self.base_url = base_url
        self.timeout_seconds = timeout_seconds

def load_config(base_url: str) -> RuntimeConfig:
    return RuntimeConfig(base_url=base_url)

from pkg.config import RuntimeConfig

class HTTPClient:
    def __init__(self, config: RuntimeConfig) -> None:
        self.config = config

    def get_status(self) -> str:
        timeout_seconds = self.config.timeout_seconds
        return f"GET {self.config.base_url}/status timeout={timeout_seconds}"

from pkg.config import load_config
from pkg.http_client import HTTPClient

def run() -> str:
    config = load_config("https://example.test")
    client = HTTPClient(config)
    return client.get_status()
